## helpers.go (new file)
```go
func parsePenceFromMoney(amount string) (int32, error) {
    f, err := strconv.ParseFloat(amount, 64)
    if err != nil {
        return 0, err
    }
    return int32(f * 100), nil
}

func buildPhones(modelMap map[string][]*handsetpb.Handset) ([]sharedmodel.MobileHandsetPhone, error) {
    phones := make([]sharedmodel.MobileHandsetPhone, 0, len(modelMap))
    for _, modelName := range sortedKeys(modelMap) {
        phone, err := buildPhone(modelName, modelMap[modelName])
        if err != nil {
            return nil, err
        }
        phones = append(phones, phone)
    }
    return phones, nil
}

func buildPhone(modelName string, hs []*handsetpb.Handset) (sharedmodel.MobileHandsetPhone, error) {
    first := hs[0]
    variants := buildVariants(hs)
    fromPrice, err := lowestPrice(hs)
    if err != nil {
        return sharedmodel.MobileHandsetPhone{}, err
    }
    return sharedmodel.MobileHandsetPhone{
        Model:              modelName,
        FromPrice:          fromPrice,
        ScreenSize:         first.GetScreenSize(),
        Battery:            first.GetBattery(),
        WiFiStandard:       first.GetWifiStandard(),
        ESim:               first.GetEsim(),
        DualSim:            first.GetDualSim(),
        SpecificationsLink: first.GetSpecificationsLink(),
        OptionTypes: []sharedmodel.MobileHandsetOptionType{
            {Key: "colour", Values: uniqueValues(hs, func(h *handsetpb.Handset) string { return h.GetColours() })},
            {Key: "storage", Values: uniqueValues(hs, func(h *handsetpb.Handset) string { return h.GetCapacity() })},
        },
        Variants: variants,
    }, nil
}

func buildVariants(hs []*handsetpb.Handset) []sharedmodel.MobileHandsetVariant {
    variants := make([]sharedmodel.MobileHandsetVariant, 0, len(hs))
    for _, h := range hs {
        variants = append(variants, sharedmodel.MobileHandsetVariant{
            ID: h.GetId(),
            Attributes: []sharedmodel.MobileHandsetAttribute{
                {Key: "colour", Value: h.GetColours()},
                {Key: "storage", Value: h.GetCapacity()},
            },
            MonthlyCharge: &sharedmodel.MobileMoney{Amount: h.GetRentalPrice().GetAmount(), Currency: h.GetRentalPrice().GetCurrency()},
            Rrp:           &sharedmodel.MobileMoney{Amount: h.GetRrp().GetAmount(), Currency: h.GetRrp().GetCurrency()},
            InStock:       h.GetInStock(),
        })
    }
    return variants
}

func lowestPrice(hs []*handsetpb.Handset) (*sharedmodel.MobileMoney, error) {
    var minPence int32
    var currency string
    for _, h := range hs {
        pence, err := parsePenceFromMoney(h.GetRentalPrice().GetAmount())
        if err != nil {
            return nil, fmt.Errorf("invalid rental price for handset %s: %w", h.GetId(), err)
        }
        if minPence == 0 || pence < minPence {
            minPence = pence
            currency = h.GetRentalPrice().GetCurrency()
        }
    }
    return &sharedmodel.MobileMoney{
        Amount:   fmt.Sprintf("%.2f", float64(minPence)/100),
        Currency: currency,
    }, nil
}

func uniqueValues(hs []*handsetpb.Handset, get func(*handsetpb.Handset) string) []string {
    seen := map[string]bool{}
    var vals []string
    for _, h := range hs {
        if v := get(h); !seen[v] {
            seen[v] = true
            vals = append(vals, v)
        }
    }
    return vals
}
```

